import { useState } from "react"
import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Plus, Pencil, Trash2, Eye, Users, BarChart3, Send, XCircle, Undo2, RotateCcw, Type, ImageIcon } from "lucide-react"
import { Button } from "@/components/ui/button"
import { formatDateTime } from "@/lib/utils"
import { Badge } from "@/components/ui/badge"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog"
import { useAdminExamList, useDeleteExam, usePublishExam, useUnpublishExam, useCloseExam, useReopenExam } from "@/hooks/use-admin-exams"
import type { Exam, ExamStatus } from "@/types"

export const Route = createFileRoute("/_layout/admin/exams/")({
  component: AdminExamListPage,
})

/** 状态 badge 样式映射 */
const STATUS_STYLE: Record<ExamStatus, string> = {
  draft: "bg-gray-100 text-gray-700 border-gray-200",
  published: "bg-green-50 text-green-700 border-green-200",
  closed: "bg-red-50 text-red-700 border-red-200",
}

const STATUS_LABEL_KEY: Record<ExamStatus, string> = {
  draft: "admin.statusDraft",
  published: "admin.statusPublished",
  closed: "admin.statusClosed",
}

function AdminExamListPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const [page, setPage] = useState(1)
  const pageSize = 10
  const { data, isLoading } = useAdminExamList(page, pageSize)

  const deleteMutation = useDeleteExam()
  const publishMutation = usePublishExam()
  const unpublishMutation = useUnpublishExam()
  const closeMutation = useCloseExam()
  const reopenMutation = useReopenExam()

  const [deleteTarget, setDeleteTarget] = useState<Exam | null>(null)
  const [showTextActions, setShowTextActions] = useState(() => {
    try {
      return localStorage.getItem("exam-admin-text-actions") === "true"
    } catch {
      return false
    }
  })

  const toggleTextActions = () => {
    setShowTextActions((v) => {
      const next = !v
      try { localStorage.setItem("exam-admin-text-actions", String(next)) } catch { /* ignore */ }
      return next
    })
  }

  const handleDelete = () => {
    if (!deleteTarget) return
    deleteMutation.mutate(deleteTarget.id, {
      onSuccess: () => {
        toast.success(t("admin.deleteSuccess"))
        setDeleteTarget(null)
      },
      onError: (err) => toast.error(err.message),
    })
  }

  const handlePublish = (id: number) => {
    publishMutation.mutate(id, {
      onSuccess: () => toast.success(t("admin.publishSuccess")),
      onError: (err) => toast.error(err.message),
    })
  }

  const handleUnpublish = (id: number) => {
    unpublishMutation.mutate(id, {
      onSuccess: () => toast.success(t("admin.unpublishSuccess")),
      onError: (err) => toast.error(err.message),
    })
  }

  const handleReopen = (id: number) => {
    reopenMutation.mutate(id, {
      onSuccess: () => toast.success(t("admin.reopenSuccess")),
      onError: (err) => toast.error(err.message),
    })
  }

  const handleClose = (id: number) => {
    closeMutation.mutate(id, {
      onSuccess: () => toast.success(t("admin.closeSuccess")),
      onError: (err) => toast.error(err.message),
    })
  }

  const totalPages = data ? Math.ceil(data.total / pageSize) : 0

  return (
    <div className="space-y-4">
      {/* 头部 */}
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold">{t("nav.examManagement")}</h1>
        <Button onClick={() => navigate({ to: "/admin/exams/create" })}>
          <Plus className="h-4 w-4" />
          {t("admin.createExam")}
        </Button>
      </div>

      {/* 表格 */}
      {isLoading ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
      ) : !data?.records.length ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
      ) : (
        <>
          <div className="rounded-lg border">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead className="min-w-[160px]">{t("admin.examTitle")}</TableHead>
                  <TableHead className="w-[90px]">{t("admin.status")}</TableHead>
                  <TableHead className="w-[100px] text-center whitespace-nowrap">{t("admin.questionCount")}</TableHead>
                  <TableHead className="w-[100px] text-center whitespace-nowrap">{t("admin.respondentCount")}</TableHead>
                  <TableHead className="w-[120px]">{t("admin.createdAt")}</TableHead>
                  <TableHead className="w-[120px]">{t("admin.updatedAt")}</TableHead>
                  <TableHead className="min-w-[260px] text-right">
                    <div className="flex items-center justify-end gap-1">
                      {t("common.actions")}
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-6 w-6"
                        title={showTextActions ? t("common.iconMode") : t("common.textMode")}
                        onClick={toggleTextActions}
                      >
                        {showTextActions ? <ImageIcon className="h-3.5 w-3.5" /> : <Type className="h-3.5 w-3.5" />}
                      </Button>
                    </div>
                  </TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {data.records.map((exam) => (
                  <TableRow key={exam.id}>
                    <TableCell className="font-medium">{exam.title}</TableCell>
                    <TableCell>
                      <Badge className={STATUS_STYLE[exam.status]}>
                        {t(STATUS_LABEL_KEY[exam.status])}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-center">{exam.questionCount}</TableCell>
                    <TableCell className="text-center">{exam.respondentCount ?? 0}</TableCell>
                    <TableCell className="text-muted-foreground text-sm whitespace-nowrap">{formatDateTime(new Date(exam.createdAt))}</TableCell>
                    <TableCell className="text-muted-foreground text-sm whitespace-nowrap">{exam.updatedAt ? formatDateTime(new Date(exam.updatedAt)) : "-"}</TableCell>
                    <TableCell>
                      <div className="flex items-center justify-end gap-0.5">
                        {/* 状态操作按钮 */}
                        {exam.status === "draft" && (
                          <>
                            <Button variant="ghost" size={showTextActions ? "sm" : "icon"} className="h-8" title={t("common.edit")} onClick={() => navigate({ to: `/admin/exams/${exam.id}/edit` })}>
                              <Pencil className="h-4 w-4" />
                              {showTextActions && <span>{t("common.edit")}</span>}
                            </Button>
                            <Button variant="ghost" size={showTextActions ? "sm" : "icon"} className="h-8 text-green-600 hover:text-green-700" title={t("admin.publish")} onClick={() => handlePublish(exam.id)}>
                              <Send className="h-4 w-4" />
                              {showTextActions && <span>{t("admin.publish")}</span>}
                            </Button>
                            <Button variant="ghost" size={showTextActions ? "sm" : "icon"} className="h-8 text-destructive hover:text-destructive" title={t("common.delete")} onClick={() => setDeleteTarget(exam)}>
                              <Trash2 className="h-4 w-4" />
                              {showTextActions && <span>{t("common.delete")}</span>}
                            </Button>
                          </>
                        )}
                        {exam.status === "published" && (
                          <>
                            <Button variant="ghost" size={showTextActions ? "sm" : "icon"} className="h-8 text-orange-500 hover:text-orange-600" title={t("admin.unpublish")} onClick={() => handleUnpublish(exam.id)}>
                              <Undo2 className="h-4 w-4" />
                              {showTextActions && <span>{t("admin.unpublish")}</span>}
                            </Button>
                            <Button variant="ghost" size={showTextActions ? "sm" : "icon"} className="h-8 text-destructive hover:text-destructive" title={t("admin.close")} onClick={() => handleClose(exam.id)}>
                              <XCircle className="h-4 w-4" />
                              {showTextActions && <span>{t("admin.close")}</span>}
                            </Button>
                          </>
                        )}
                        {exam.status === "closed" && (
                          <>
                            <Button variant="ghost" size={showTextActions ? "sm" : "icon"} className="h-8 text-blue-500 hover:text-blue-600" title={t("admin.reopen")} onClick={() => handleReopen(exam.id)}>
                              <RotateCcw className="h-4 w-4" />
                              {showTextActions && <span>{t("admin.reopen")}</span>}
                            </Button>
                            <Button variant="ghost" size={showTextActions ? "sm" : "icon"} className="h-8 text-destructive hover:text-destructive" title={t("common.delete")} onClick={() => setDeleteTarget(exam)}>
                              <Trash2 className="h-4 w-4" />
                              {showTextActions && <span>{t("common.delete")}</span>}
                            </Button>
                          </>
                        )}
                        {/* 分隔线 */}
                        <div className="mx-1 h-4 w-px bg-border" />
                        {/* 通用操作按钮 */}
                        <Button variant="ghost" size={showTextActions ? "sm" : "icon"} className="h-8" title={t("admin.manageQuestions")} onClick={() => navigate({ to: `/admin/exams/${exam.id}/questions` })}>
                          <Eye className="h-4 w-4" />
                          {showTextActions && <span>{t("admin.manageQuestions")}</span>}
                        </Button>
                        <Button variant="ghost" size={showTextActions ? "sm" : "icon"} className="h-8" title={t("admin.whitelist")} onClick={() => navigate({ to: `/admin/exams/${exam.id}/whitelist` })}>
                          <Users className="h-4 w-4" />
                          {showTextActions && <span>{t("admin.whitelist")}</span>}
                        </Button>
                        <Button variant="ghost" size={showTextActions ? "sm" : "icon"} className="h-8" title={t("admin.analysisTab")} onClick={() => navigate({ to: `/admin/exams/${exam.id}/analysis` })}>
                          <BarChart3 className="h-4 w-4" />
                          {showTextActions && <span>{t("admin.analysisTab")}</span>}
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>

          {/* 分页 */}
          {totalPages > 1 && (
            <div className="flex items-center justify-end gap-2">
              <Button
                variant="outline"
                size="sm"
                disabled={page <= 1}
                onClick={() => setPage((p) => p - 1)}
              >
                {t("admin.prevPage")}
              </Button>
              <span className="text-sm text-muted-foreground">
                {page} / {totalPages}
              </span>
              <Button
                variant="outline"
                size="sm"
                disabled={page >= totalPages}
                onClick={() => setPage((p) => p + 1)}
              >
                {t("admin.nextPage")}
              </Button>
            </div>
          )}
        </>
      )}

      {/* 删除确认弹窗 */}
      <Dialog open={!!deleteTarget} onOpenChange={(open) => !open && setDeleteTarget(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("admin.confirmDelete")}</DialogTitle>
            <DialogDescription>
              {t("admin.confirmDeleteDesc", { title: deleteTarget?.title })}
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDeleteTarget(null)}>
              {t("common.cancel")}
            </Button>
            <Button variant="destructive" onClick={handleDelete} disabled={deleteMutation.isPending}>
              {t("common.delete")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

import i18n from "i18next"
import { initReactI18next } from "react-i18next"
import en from "./en.json"
import zh from "./zh.json"

i18n.use(initReactI18next).init({
  resources: {
    zh: { translation: zh },
    en: { translation: en },
  },
  lng: "zh",
  fallbackLng: "zh",
  interpolation: {
    escapeValue: false,
  },
})

export default i18n

import { useState, useRef, Fragment } from "react"
import { createFileRoute, useNavigate, useParams } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { ArrowLeft, Plus, Pencil, Trash2, Upload, Download, Lock, ChevronDown, ChevronRight } from "lucide-react"
import { Button } from "@/components/ui/button"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog"
import { Textarea } from "@/components/ui/textarea"
import { QuestionForm } from "@/components/question-form"
import {
  useQuestionList,
  useAddQuestion,
  useBatchImport,
  useUpdateQuestion,
  useDeleteQuestion,
} from "@/hooks/use-admin-questions"
import { useAdminExamDetail } from "@/hooks/use-admin-exams"
import type { Question } from "@/types"

export const Route = createFileRoute("/_layout/admin/exams/$id/questions")({
  component: ManageQuestionsPage,
})

function ManageQuestionsPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = useParams({ from: "/_layout/admin/exams/$id/questions" })
  const examId = Number(id)

  const { data: exam } = useAdminExamDetail(examId)
  const readonly = exam?.status !== "draft"

  const { data: questions, isLoading } = useQuestionList(examId)
  const addMutation = useAddQuestion()
  const batchImportMutation = useBatchImport()
  const updateMutation = useUpdateQuestion()
  const deleteMutation = useDeleteQuestion()

  const [showAddDialog, setShowAddDialog] = useState(false)
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null)
  const [deleteTarget, setDeleteTarget] = useState<Question | null>(null)
  const [showImportDialog, setShowImportDialog] = useState(false)
  const [importPreview, setImportPreview] = useState<Partial<Question>[] | null>(null)
  const [pasteText, setPasteText] = useState("")
  const [expandedId, setExpandedId] = useState<number | null>(null)
  const fileInputRef = useRef<HTMLInputElement>(null)

  const handleAdd = (data: Partial<Question>) => {
    addMutation.mutate(
      { examId, ...data },
      {
        onSuccess: () => {
          toast.success(t("admin.addQuestionSuccess"))
          setShowAddDialog(false)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const handleUpdate = (data: Partial<Question>) => {
    if (!editingQuestion) return
    updateMutation.mutate(
      { examId, id: editingQuestion.id, ...data },
      {
        onSuccess: () => {
          toast.success(t("admin.updateSuccess"))
          setEditingQuestion(null)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const handleDelete = () => {
    if (!deleteTarget) return
    deleteMutation.mutate(
      { examId, id: deleteTarget.id },
      {
        onSuccess: () => {
          toast.success(t("admin.deleteSuccess"))
          setDeleteTarget(null)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const REQUIRED_FIELDS = ["content", "optionA", "optionB", "optionC", "optionD", "correctAnswer"] as const

  /** 校验单条题目数据 */
  const validateQuestion = (item: Record<string, unknown>, index: number): string | null => {
    for (const field of REQUIRED_FIELDS) {
      if (!item[field] || typeof item[field] !== "string" || !(item[field] as string).trim()) {
        return t("admin.invalidQuestionData", { index: index + 1 })
      }
    }
    if (!/^[ABCD]$/.test(item.correctAnswer as string)) {
      return t("admin.invalidQuestionData", { index: index + 1 })
    }
    return null
  }

  /** 解析 JSON 文本并校验 */
  const parseAndValidate = (text: string): Partial<Question>[] | null => {
    try {
      const parsed = JSON.parse(text)
      const items = Array.isArray(parsed) ? parsed : parsed.questions
      if (!Array.isArray(items) || items.length === 0) {
        toast.error(t("admin.invalidJsonFormat"))
        return null
      }
      for (let i = 0; i < items.length; i++) {
        const err = validateQuestion(items[i], i)
        if (err) {
          toast.error(err)
          return null
        }
      }
      return items
    } catch {
      toast.error(t("admin.invalidJsonFormat"))
      return null
    }
  }

  /** 处理文件选择 */
  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return
    const reader = new FileReader()
    reader.onload = (event) => {
      const text = event.target?.result as string
      const items = parseAndValidate(text)
      if (items) {
        setPasteText(text)
        setImportPreview(items)
      }
    }
    reader.onerror = () => toast.error(t("admin.fileReadError"))
    reader.readAsText(file)
    e.target.value = ""
  }

  /** 处理粘贴文本解析 */
  const handleParsePaste = () => {
    if (!pasteText.trim()) return
    const items = parseAndValidate(pasteText)
    if (items) setImportPreview(items)
  }

  /** 确认导入 */
  const handleImportConfirm = () => {
    if (!importPreview) return
    batchImportMutation.mutate(
      { examId, questions: importPreview },
      {
        onSuccess: () => {
          toast.success(t("admin.importSuccess", { count: importPreview.length }))
          setShowImportDialog(false)
          setImportPreview(null)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  /** 下载 JSON 模板 */
  const handleDownloadTemplate = () => {
    const template = [
      {
        content: "示例题目 / Example question",
        optionA: "选项A / Option A",
        optionB: "选项B / Option B",
        optionC: "选项C / Option C",
        optionD: "选项D / Option D",
        correctAnswer: "A",
        analysis: "解析说明（可选）/ Analysis (optional)",
      },
    ]
    const blob = new Blob([JSON.stringify(template, null, 2)], { type: "application/json" })
    const url = URL.createObjectURL(blob)
    const a = document.createElement("a")
    a.href = url
    a.download = "questions-template.json"
    a.click()
    URL.revokeObjectURL(url)
  }

  /** 关闭导入弹窗 */
  const closeImportDialog = () => {
    setShowImportDialog(false)
    setImportPreview(null)
    setPasteText("")
  }

  /** 截断文本显示 */
  const truncate = (text: string, maxLen = 50) =>
    text.length > maxLen ? `${text.slice(0, maxLen)}...` : text

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Button variant="ghost" size="icon" onClick={() => navigate({ to: "/admin/exams" })}>
            <ArrowLeft className="h-4 w-4" />
          </Button>
          <h1 className="text-xl font-semibold">{t("admin.manageQuestions")}</h1>
        </div>
        {!readonly && (
          <div className="flex gap-2">
            <Button variant="outline" onClick={() => setShowImportDialog(true)}>
              <Upload className="h-4 w-4" />
              {t("admin.importQuestions")}
            </Button>
            <Button onClick={() => setShowAddDialog(true)}>
              <Plus className="h-4 w-4" />
              {t("admin.addQuestion")}
            </Button>
          </div>
        )}
      </div>

      {readonly && (
        <div className="flex items-center gap-2 rounded-md border border-orange-200 bg-orange-50 px-4 py-3 text-sm text-orange-700">
          <Lock className="h-4 w-4 shrink-0" />
          <span>{t("admin.questionsReadonly")}</span>
        </div>
      )}

      {isLoading ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
      ) : !questions?.length ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
      ) : (
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead className="w-16">#</TableHead>
              <TableHead>{t("admin.questionContent")}</TableHead>
              <TableHead className="w-24">{t("admin.correctAnswer")}</TableHead>
              {!readonly && <TableHead className="w-24 text-right">{t("common.actions")}</TableHead>}
            </TableRow>
          </TableHeader>
          <TableBody>
            {questions.map((q) => {
              const isExpanded = expandedId === q.id
              const colCount = readonly ? 3 : 4
              return (
                <Fragment key={q.id}>
                  <TableRow
                    className="cursor-pointer hover:bg-muted/50"
                    onClick={() => setExpandedId(isExpanded ? null : q.id)}
                  >
                    <TableCell>
                      <div className="flex items-center gap-1">
                        {isExpanded ? <ChevronDown className="h-3 w-3" /> : <ChevronRight className="h-3 w-3" />}
                        {q.sortOrder}
                      </div>
                    </TableCell>
                    <TableCell>{truncate(q.content)}</TableCell>
                    <TableCell>{q.correctAnswer}</TableCell>
                    {!readonly && (
                      <TableCell>
                        <div className="flex justify-end gap-1" onClick={(e) => e.stopPropagation()}>
                          <Button
                            variant="ghost"
                            size="icon"
                            title={t("common.edit")}
                            onClick={() => setEditingQuestion(q)}
                          >
                            <Pencil className="h-4 w-4" />
                          </Button>
                          <Button
                            variant="ghost"
                            size="icon"
                            title={t("common.delete")}
                            onClick={() => setDeleteTarget(q)}
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </TableCell>
                    )}
                  </TableRow>
                  {isExpanded && (
                    <TableRow key={`${q.id}-options`}>
                      <TableCell colSpan={colCount} className="bg-muted/30 py-3">
                        <div className="grid grid-cols-2 gap-x-8 gap-y-2 pl-8 text-sm">
                          {(["A", "B", "C", "D"] as const).map((key) => {
                            const optionKey = `option${key}` as keyof Question
                            const isCorrect = q.correctAnswer === key
                            return (
                              <div key={key} className={isCorrect ? "font-semibold text-green-700" : "text-muted-foreground"}>
                                {key}. {q[optionKey] as string}
                                {isCorrect && " ✓"}
                              </div>
                            )
                          })}
                          {q.analysis && (
                            <div className="col-span-2 mt-1 text-muted-foreground">
                              {t("admin.analysis")}: {q.analysis}
                            </div>
                          )}
                        </div>
                      </TableCell>
                    </TableRow>
                  )}
                </Fragment>
              )
            })}
          </TableBody>
        </Table>
      )}

      {/* 新增题目弹窗 */}
      <Dialog open={showAddDialog} onOpenChange={setShowAddDialog}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{t("admin.addQuestion")}</DialogTitle>
          </DialogHeader>
          <QuestionForm onSubmit={handleAdd} onCancel={() => setShowAddDialog(false)} />
        </DialogContent>
      </Dialog>

      {/* 编辑题目弹窗 */}
      <Dialog open={!!editingQuestion} onOpenChange={(open) => !open && setEditingQuestion(null)}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{t("admin.editQuestion")}</DialogTitle>
          </DialogHeader>
          {editingQuestion && (
            <QuestionForm
              defaultValues={editingQuestion}
              onSubmit={handleUpdate}
              onCancel={() => setEditingQuestion(null)}
            />
          )}
        </DialogContent>
      </Dialog>

      {/* 删除确认弹窗 */}
      <Dialog open={!!deleteTarget} onOpenChange={(open) => !open && setDeleteTarget(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("admin.confirmDelete")}</DialogTitle>
            <DialogDescription>{t("admin.confirmDeleteQuestionDesc")}</DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDeleteTarget(null)}>
              {t("common.cancel")}
            </Button>
            <Button variant="destructive" onClick={handleDelete} disabled={deleteMutation.isPending}>
              {t("common.delete")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
      {/* 导入题目弹窗 */}
      <Dialog open={showImportDialog} onOpenChange={(open) => !open && closeImportDialog()}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("admin.importQuestions")}</DialogTitle>
            <DialogDescription>{t("admin.importQuestionsDesc")}</DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <Textarea
              rows={8}
              placeholder={t("admin.pasteJsonPlaceholder")}
              value={pasteText}
              onChange={(e) => {
                setPasteText(e.target.value)
                setImportPreview(null)
              }}
            />
            <div className="flex gap-2">
              <Button variant="outline" onClick={handleParsePaste} disabled={!pasteText.trim()}>
                {t("admin.parseJson")}
              </Button>
              <Button variant="outline" onClick={() => fileInputRef.current?.click()}>
                <Upload className="h-4 w-4" />
                {t("admin.selectFile")}
              </Button>
              <Button variant="ghost" onClick={handleDownloadTemplate}>
                <Download className="h-4 w-4" />
                {t("admin.downloadTemplate")}
              </Button>
              <input
                ref={fileInputRef}
                type="file"
                accept=".json"
                className="hidden"
                onChange={handleFileSelect}
              />
            </div>
            {importPreview && (
              <div className="rounded-md border p-3 space-y-2">
                <p className="text-sm font-medium">
                  {t("admin.importPreview", { count: importPreview.length })}
                </p>
                <div className="max-h-48 overflow-y-auto space-y-1">
                  {importPreview.slice(0, 10).map((q, i) => (
                    <div key={i} className="text-sm text-muted-foreground">
                      {i + 1}. {truncate(q.content ?? "", 60)}
                    </div>
                  ))}
                  {importPreview.length > 10 && (
                    <div className="text-sm text-muted-foreground">...</div>
                  )}
                </div>
              </div>
            )}
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={closeImportDialog}>
              {t("common.cancel")}
            </Button>
            <Button
              onClick={handleImportConfirm}
              disabled={!importPreview || batchImportMutation.isPending}
            >
              {t("common.confirm")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

