import { createFileRoute, useNavigate, useParams } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { ArrowLeft } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { formatDateTime } from "@/lib/utils"
import { useAdminExamDetail } from "@/hooks/use-admin-exams"
import type { ExamStatus, AccessMode } from "@/types"

export const Route = createFileRoute("/_layout/admin/exams/$id/detail")({
  component: ExamDetailPage,
})

const STATUS_STYLE: Record<ExamStatus, string> = {
  draft: "bg-gray-100 text-gray-700 border-gray-200",
  published: "bg-green-50 text-green-700 border-green-200",
  closed: "bg-red-50 text-red-700 border-red-200",
}

const STATUS_LABEL_KEY: Record<ExamStatus, string> = {
  draft: "admin.statusDraft",
  published: "admin.statusPublished",
  closed: "admin.statusClosed",
}

const ACCESS_MODE_LABEL_KEY: Record<AccessMode, string> = {
  open: "admin.accessOpen",
  whitelist: "admin.accessWhitelist",
}

function ExamDetailPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = useParams({ from: "/_layout/admin/exams/$id/detail" })
  const examId = Number(id)

  const { data: exam, isLoading } = useAdminExamDetail(examId)

  if (isLoading) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
  }

  if (!exam) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
  }

  /** 信息项组件 */
  const InfoItem = ({ label, children }: { label: string; children: React.ReactNode }) => (
    <div className="flex items-center justify-between py-2 border-b last:border-b-0">
      <span className="text-sm text-muted-foreground">{label}</span>
      <span className="text-sm font-medium">{children}</span>
    </div>
  )

  return (
    <div className="space-y-4">
      {/* 顶部 */}
      <div className="flex items-center gap-2">
        <Button variant="ghost" size="icon" onClick={() => navigate({ to: "/admin/exams" })}>
          <ArrowLeft className="h-4 w-4" />
        </Button>
        <h1 className="text-xl font-semibold">{t("admin.examDetail")}</h1>
      </div>

      {/* 试卷信息卡片 */}
      <div className="rounded-lg border p-6 max-w-xl space-y-1">
        <h2 className="text-lg font-semibold mb-4">{exam.title}</h2>
        <InfoItem label={t("admin.status")}>
          <Badge className={STATUS_STYLE[exam.status]}>
            {t(STATUS_LABEL_KEY[exam.status])}
          </Badge>
        </InfoItem>
        <InfoItem label={t("admin.questionCount")}>{exam.questionCount}</InfoItem>
        <InfoItem label={t("admin.respondentCount")}>{exam.respondentCount ?? 0}</InfoItem>
        <InfoItem label={t("admin.timeLimit")}>
          {exam.timeLimitMin > 0 ? `${exam.timeLimitMin} ${t("exam.questionUnit") || "min"}` : t("exam.noTimeLimit")}
        </InfoItem>
        <InfoItem label={t("admin.maxAttempts")}>
          {exam.maxAttempts > 0 ? exam.maxAttempts : t("exam.unlimited")}
        </InfoItem>
        <InfoItem label={t("admin.accessMode")}>{t(ACCESS_MODE_LABEL_KEY[exam.accessMode])}</InfoItem>
        <InfoItem label={t("admin.showAnswer")}>{exam.showAnswer ? t("common.yes") : t("common.no")}</InfoItem>
        <InfoItem label={t("admin.showAnalysis")}>{exam.showAnalysis ? t("common.yes") : t("common.no")}</InfoItem>
        <InfoItem label={t("admin.createdAt")}>{formatDateTime(new Date(exam.createdAt))}</InfoItem>
        <InfoItem label={t("admin.updatedAt")}>{exam.updatedAt ? formatDateTime(new Date(exam.updatedAt)) : "-"}</InfoItem>
      </div>
    </div>
  )
}

