import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Switch } from "@/components/ui/switch"

export const Route = createFileRoute("/login")({
  component: LoginPage,
})

function LoginPage() {
  const { t } = useTranslation()
  const [username, setUsername] = useState("")
  const [isAdmin, setIsAdmin] = useState(false)
  const [loading, setLoading] = useState(false)

  // 已登录则跳转到考试列表
  if (getToken()) {
    return <Navigate to="/exams" />
  }

  const handleOAuthLogin = () => {
    window.location.href = "/api/auth/oauth2/login"
  }

  const handleDevLogin = async () => {
    if (!username.trim()) return
    setLoading(true)
    try {
      const res = await post<{ token: string }>("/api/auth/oauth2/dev-login", {
        username: username.trim(),
        isAdmin,
      })
      setToken(res.token)
      window.location.href = "/exams"
    } catch {
      setLoading(false)
    }
  }

  return (
    <div className="flex min-h-screen items-center justify-center bg-gray-50">
      <div className="w-full max-w-sm rounded-lg border bg-white p-8 shadow-sm">
        <div className="mb-6 text-center">
          <h1 className="text-2xl font-bold">考试系统</h1>
          <p className="mt-2 text-sm text-muted-foreground">
            请使用 OA 账号登录以继续
          </p>
        </div>

        <Button className="w-full" size="lg" onClick={handleOAuthLogin}>
          {t("auth.loginWithOA")}
        </Button>

        {/* 本地登录（dev 环境） */}
        <div className="mt-6 border-t pt-6">
          <p className="mb-4 text-center text-sm text-muted-foreground">{t("auth.devLoginTitle")}</p>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="username">{t("auth.username")}</Label>
              <Input
                id="username"
                placeholder={t("auth.usernamePlaceholder")}
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && handleDevLogin()}
              />
            </div>
            <div className="flex items-center justify-between">
              <Label htmlFor="isAdmin">{t("auth.adminRole")}</Label>
              <Switch
                id="isAdmin"
                checked={isAdmin}
                onCheckedChange={setIsAdmin}
              />
            </div>
            <Button
              className="w-full"
              variant="outline"
              onClick={handleDevLogin}
              disabled={!username.trim() || loading}
            >
              {t("auth.devLogin")}
            </Button>
          </div>
        </div>
      </div>
    </div>
  )
}

