175→    private String exchangeAccessToken(String code, String redirectUri) {
176→        log.info("[lbl][Auth][OAUTH] 换取 access_token, tokenUri={}, redirectUri={}", tokenUri, redirectUri);
177→        HttpHeaders headers = new HttpHeaders();
178→        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
179→        headers.setBasicAuth(clientId, clientSecret);
180→
181→        MultiValueMap<String, String> params = new LinkedMultiValueMap<>();
182→        params.add("grant_type", "authorization_code");
183→        params.add("code", code);
184→        params.add("redirect_uri", redirectUri);
185→
186→        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(params, headers);
187→
